"use client";

import type { EditorMessageKind } from "@/components/editor/types";
import WaveSurfer from "wavesurfer.js";
import RegionsPlugin, {
  Region,
} from "wavesurfer.js/dist/plugins/regions.esm.js";
import { useCallback, useEffect, useRef, useState } from "react";

interface UseWaveformEditorOptions {
  messageKind: EditorMessageKind;
  onClearMessageUnlessLoading: () => void;
  onError: () => void;
  proxiedAudioUrl: string | null;
}

export default function useWaveformEditor({
  messageKind,
  onClearMessageUnlessLoading,
  onError,
  proxiedAudioUrl,
}: UseWaveformEditorOptions) {
  const waveformRef = useRef<HTMLDivElement>(null);
  const wavesurferRef = useRef<WaveSurfer | null>(null);
  const regionsRef = useRef<RegionsPlugin | null>(null);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [waveformLoading, setWaveformLoading] = useState<boolean>(false);

  const resetWaveform = useCallback(() => {
    setWaveformLoading(false);
    wavesurferRef.current?.stop();
    regionsRef.current?.getRegions().forEach((region) => region.remove());
  }, []);

  const loadWaveform = useCallback(
    (audioUrl: string) => {
      if (!wavesurferRef.current) {
        return;
      }

      if (messageKind !== "ffmpeg-loading") {
        onClearMessageUnlessLoading();
      }

      setWaveformLoading(true);
      wavesurferRef.current.stop();
      regionsRef.current?.getRegions().forEach((region) => region.remove());
      wavesurferRef.current.load(audioUrl);
    },
    [messageKind, onClearMessageUnlessLoading],
  );

  useEffect(() => {
    if (!waveformRef.current || wavesurferRef.current) {
      return;
    }

    wavesurferRef.current = WaveSurfer.create({
      container: waveformRef.current,
      waveColor: "#b8d6d8",
      progressColor: "#ff6b4a",
      cursorColor: "#0f3f45",
      barWidth: 3,
      barRadius: 6,
      height: 136,
      normalize: true,
    });

    const wsRegions = wavesurferRef.current.registerPlugin(
      RegionsPlugin.create(),
    );
    regionsRef.current = wsRegions;

    wavesurferRef.current.on("decode", (decodedDuration: number) => {
      setWaveformLoading(false);
      onClearMessageUnlessLoading();
      wsRegions.getRegions().forEach((region) => region.remove());
      wsRegions.addRegion({
        start: 0,
        end: Math.min(30, decodedDuration),
        color: "rgba(255, 107, 74, 0.18)",
        drag: true,
        resize: true,
      });
    });

    wavesurferRef.current.on("play", () => setIsPlaying(true));
    wavesurferRef.current.on("pause", () => setIsPlaying(false));
    wavesurferRef.current.on("error", (error) => {
      console.error("Waveform load error", error);
      setWaveformLoading(false);
      onError();
    });

    wsRegions.on("region-updated", (region: Region) => {
      if (region.end - region.start > 30) {
        region.setOptions({ end: region.start + 30 });
      }
      region.play();
    });

    wsRegions.on("region-out", (region) => {
      region.play();
    });

    return () => {
      wavesurferRef.current?.destroy();
      wavesurferRef.current = null;
    };
  }, [onClearMessageUnlessLoading, onError]);

  useEffect(() => {
    try {
      if (proxiedAudioUrl) {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        loadWaveform(proxiedAudioUrl);
        return;
      }

      resetWaveform();
    } catch (error) {
      console.log("error: ", error);
      setWaveformLoading(false);
      onError();
    }
  }, [
    loadWaveform,
    onClearMessageUnlessLoading,
    onError,
    proxiedAudioUrl,
    resetWaveform,
  ]);

  return {
    isPlaying,
    regionsRef,
    waveformLoading,
    waveformRef,
    wavesurferRef,
  };
}
