"use client";

import type { EditorMessageKind } from "@/components/editor/types";
import { useCallback, useEffect, useRef, useState } from "react";

export default function useEditorMessage() {
  const messageRef = useRef<HTMLDivElement>(null);
  const messageKindRef = useRef<EditorMessageKind>("default");
  const [message, setMessage] = useState<string | null>(null);
  const [messageKind, setMessageKind] = useState<EditorMessageKind>("default");
  const [highlightMessage, setHighlightMessage] = useState<boolean>(false);

  const focusMessage = useCallback(() => {
    setHighlightMessage(true);

    requestAnimationFrame(() => {
      messageRef.current?.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
      messageRef.current?.focus();
    });

    window.setTimeout(() => {
      setHighlightMessage(false);
    }, 1800);
  }, []);

  useEffect(() => {
    messageKindRef.current = messageKind;
  }, [messageKind]);

  const clearMessageUnlessLoading = useCallback(() => {
    setMessage((current) =>
      messageKindRef.current === "ffmpeg-loading" ? current : null,
    );
  }, []);

  return {
    clearMessageUnlessLoading,
    focusMessage,
    highlightMessage,
    message,
    messageKind,
    messageRef,
    setMessage,
    setMessageKind,
  };
}
